import{_ as e,c as t,o as r,ag as s}from"./chunks/framework.Co20b0ok.js";const n="/assets/image%2014.5LlYSpOJ.png",p=JSON.parse('{"title":"SMB & IPC & RPC","description":"","frontmatter":{},"headers":[],"relativePath":"study/domain/SMB & IPC & RPC.md","filePath":"study/domain/SMB & IPC & RPC.md"}'),a={name:"study/domain/SMB & IPC & RPC.md"};function i(l,o,c,d,C,g){return r(),t("div",null,o[0]||(o[0]=[s('<h1 id="smb-ipc-rpc" tabindex="-1">SMB &amp; IPC &amp; RPC <a class="header-anchor" href="#smb-ipc-rpc" aria-label="Permalink to &quot;SMB &amp; IPC &amp; RPC&quot;">​</a></h1><h3 id="_1-smb-server-message-block-445" tabindex="-1">1. <strong>SMB (Server Message Block) 445</strong> <a class="header-anchor" href="#_1-smb-server-message-block-445" aria-label="Permalink to &quot;1. **SMB (Server Message Block) 445**&quot;">​</a></h3><p><strong>SMB</strong> 是一种网络文件共享协议，允许应用程序读取、写入远程服务器上的文件，以及进行远程服务器资源的通信（如打印机）。在你的数据包中，SMB2 协议被多次提及，表明正在进行文件共享、目录枚举等操作。</p><ul><li><strong>SMB2</strong>：是 SMB 协议的更新版本，较 SMB1 更高效，主要用于现代 Windows 系统。</li><li><strong>常见操作</strong>： <ul><li><strong>Tree Connect</strong>：请求建立对共享资源（如文件夹）的连接。</li><li><strong>Create Response File</strong>：表示创建文件时的响应。</li><li><strong>EnumDomains</strong>：枚举域信息，可能在进行域控制器或其他网络信息收集时使用。</li></ul></li></ul><h3 id="_2-dcerpc-distributed-component-object-model-rpc-135" tabindex="-1">2. <strong>DCERPC (Distributed Component Object Model RPC) 135</strong> <a class="header-anchor" href="#_2-dcerpc-distributed-component-object-model-rpc-135" aria-label="Permalink to &quot;2. **DCERPC (Distributed Component Object Model RPC) 135**&quot;">​</a></h3><p><strong>DCERPC</strong> 是一种协议，用于在分布式计算机系统上进行远程过程调用。它基于 <strong>RPC</strong>（Remote Procedure Call）协议，使得应用程序能够调用另一台计算机上的方法。DCERPC 是用于访问系统服务的关键协议，尤其在 Windows 系统中用于很多管理和远程执行功能。</p><ul><li><strong>常见操作</strong>： <ul><li><strong>Read Request</strong> 和 <strong>Response</strong>：表示尝试读取某些文件或资源。</li><li><strong>QueryDisplayInfo</strong>：查询显示信息，通常用于远程获取系统的用户信息或状态。</li><li><strong>STATUS_MORE_ENTRIES</strong>：表明返回的查询结果分页，还需要更多的数据包来完成请求。</li></ul></li></ul><h3 id="_3-ipc-inter-process-communication" tabindex="-1">3. <strong>IPC (Inter-Process Communication)</strong> <a class="header-anchor" href="#_3-ipc-inter-process-communication" aria-label="Permalink to &quot;3. **IPC (Inter-Process Communication)**&quot;">​</a></h3><p><strong>IPC</strong> 是一种机制，允许在同一计算机或不同计算机上的进程之间进行通信。在 Windows 系统中，<code>$IPC</code> 共享用于系统进程间的通信，而 <code>IPC$</code> 共享通常不会显示在常规的网络共享列表中，它是隐式的。</p><ul><li><strong>$IPC</strong> 用于远程过程调用（RPC），通过 <code>\\\\ip\\$IPC</code> 共享来进行进程间通信。这个共享并不存储普通文件，而是用于系统之间的内部通信（如管理任务、服务交互等）。</li></ul><h3 id="它们如何协同工作" tabindex="-1">它们如何协同工作？ <a class="header-anchor" href="#它们如何协同工作" aria-label="Permalink to &quot;它们如何协同工作？&quot;">​</a></h3><ul><li><p><strong>SMB 和 IPC</strong>：在网络上，SMB 用于文件和资源共享，而 <code>$IPC</code> 共享用于处理远程管理和进程间通信。通过 <code>$IPC</code>，Windows 系统可以让远程计算机执行特定任务（如调用远程过程）。</p></li><li><p><strong>SMB 和 DCERPC</strong>：当系统执行远程管理任务时，可能会通过 SMB 协议建立连接，再使用 DCERPC 进行远程过程调用。例如，通过 DCERPC 查询或更改系统配置时，SMB 负责建立连接。</p><p><img src="'+n+'" alt="image.png"></p></li><li><p><strong>DCERPC 和 IPC</strong>：DCERPC 也可以通过 IPC 管道传输数据。通过 <code>$IPC</code>，你可以执行远程命令或查询系统状态，而 DCERPC 提供了通过网络进行调用的机制。</p></li></ul><h3 id="渗透测试中的应用" tabindex="-1">渗透测试中的应用： <a class="header-anchor" href="#渗透测试中的应用" aria-label="Permalink to &quot;渗透测试中的应用：&quot;">​</a></h3><p>在渗透测试中，这些协议的流量常常是攻击者尝试获取远程机器信息、提升权限、执行命令或绕过防护的目标。</p><ol><li><strong>SMB</strong>：可以通过暴力破解 SMB 登录凭据来进行渗透，或者利用 SMB 漏洞（如 EternalBlue）进行远程代码执行。</li><li><strong>DCERPC</strong>：可以用于通过远程过程调用执行命令、获取系统信息，甚至进行横向移动（例如利用已知的漏洞如 MS08-067）。</li><li><strong>IPC</strong>：通过 <code>$IPC</code>，攻击者可以与远程计算机的进程进行通信，可能执行远程管理任务或者绕过某些安全控制。</li></ol>',15)]))}const m=e(a,[["render",i]]);export{p as __pageData,m as default};
